import React, { useEffect, useState } from "react";
import { getFreelancerDashboard } from "../../api/api";

const FreelancerDashboard = () => {

  const [data, setData] = useState({
    activeProjects: 0,
    pendingProposals: 0,
    projects: []
  });

  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchDashboard = async () => {
      try {
        const res = await getFreelancerDashboard();
        setData(res.data);
      } catch (err) {
        console.log("Dashboard Error:", err.response?.data || err.message);
      } finally {
        setLoading(false);
      }
    };

    fetchDashboard();
  }, []);

  if (loading) return <div>Loading...</div>;

  return (
    <div className="max-w-7xl mx-auto">

      {/* Header */}
      <div className="mb-10">
        <h1 className="text-3xl font-bold text-gray-800">
          Welcome back 👋
        </h1>
        <p className="text-gray-500 mt-2">
          Here's your freelancing overview
        </p>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-12">

        <StatCard title="Active Projects" value={data.activeProjects} />

        <StatCard title="Pending Proposals" value={data.pendingProposals} />

      </div>

      {/* Active Projects */}
      <div className="bg-white p-6 rounded-2xl shadow-sm border">
        <h2 className="text-xl font-semibold mb-4">
          Your Projects
        </h2>

        {data.projects.length === 0 ? (
          <p className="text-gray-500">No projects yet</p>
        ) : (
          data.projects.map((project) => (
            <div key={project.id} className="border rounded-xl p-5 mb-4">
              <h3 className="text-lg font-semibold">
                {project.title}
              </h3>

              <p className="text-gray-500 mt-2 mb-4">
                {project.description}
              </p>

              <div className="text-sm text-gray-500">
                ₹{project.budget}
              </div>
            </div>
          ))
        )}
      </div>

    </div>
  );
};

const StatCard = ({ title, value }) => (
  <div className="bg-white p-6 rounded-2xl shadow-sm border">
    <h4 className="text-gray-500 text-sm">{title}</h4>
    <h2 className="text-3xl font-bold mt-2">{value}</h2>
  </div>
);

export default FreelancerDashboard;
